"use client";
import BatchProcessing from "@/app/batch-processing/page";

export default function HomePage() {
  return (
    <div>
      <BatchProcessing />
    </div>
  );
}

"use client";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Button } from "@/components/ui/button";
import { useRef, useState, useEffect } from "react";
import { getSession, useSession } from "next-auth/react";
import {
  BatchCreateError,
  NormalizedValidationError,
  useBatchList,
  useCreateBatch,
  usePipelines,
  useRetryBatch,
  useBatchRunStatus,
  useServiceAccountEmail,
  useDrivePreview,
  DrivePreviewResponse,
  BatchListItem,
  useJobs,
  Job,
  formatJobDisplay,
} from "@/lib/api/batch";
import { DrivePreviewPanel } from "@/components/DrivePreviewPanel";
import { DrivePreviewDialog } from "@/components/DrivePreviewDialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Copy, Check, Download, RefreshCw, Upload } from "lucide-react";
import Pagination from "@/components/Pagination";
import { toast } from "sonner";
import { Input } from "@/components/ui/input";
import IndeterminateProgress from "@/components/ui/progress-indeterminate";
import { useQueryClient } from "@tanstack/react-query";
import { BatchDetailDialog } from "@/components/BatchDetailDialog";
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";
import { notifyBatchComplete, requestNotificationPermission } from "@/lib/utils/notify";

function normalizeValidationError(
  error: BatchCreateError | null,
): NormalizedValidationError | null {
  if (!error?.detail) return null;

  const detail = error.detail;
  const files = Array.isArray(detail.files) ? detail.files : [];
  const issues = Array.isArray(detail.issues) ? detail.issues : [];

  if (!files.length && !issues.length) return null;

  const issueLines = issues.map((issue) => {
    const row = typeof issue.row === "number" ? issue.row : "unknown";
    const directory = issue.directory || "unknown directory";
    const promptColumn = issue.prompt_column || "unknown prompt column";
    const imageColumn = issue.image_column || "unknown image column";
    return `Row ${row} (${directory}): prompt column "${promptColumn}" is missing required image in "${imageColumn}"`;
  });

  const items = [...files, ...issueLines];
  const count = typeof detail.count === "number" ? detail.count : items.length;

  return {
    message: detail.error || "Validation error",
    count,
    itemLabel: files.length > 0 && issues.length === 0 ? "missing file(s)" : "issue(s)",
    items,
  };
}

export default function BatchProcessing() {
  const [batchName, setBatchName] = useState("");
  const [itemsPerPage, setItemsPerPage] = useState(20);
  const [page, setPage] = useState(1);
  const [zipFile, setZipFile] = useState<File | null>(null);
  const [csvFile, setCsvFile] = useState<File | null>(null);
  const [selectedPipeline, setSelectedPipeline] = useState<string>("");
  const [scheduledAt, setScheduledAt] = useState<Date | null>(null);
  const [showSchedulePicker, setShowSchedulePicker] = useState(false);
  const [selectedBatchId, setSelectedBatchId] = useState<string | null>(null);
  const [selectedBatchData, setSelectedBatchData] = useState<BatchListItem | null>(null);
  const [selectedJob, setSelectedJob] = useState<string>("");
  const [showJobDialog, setShowJobDialog] = useState(false);
  const [pendingBatchDialog, setPendingBatchDialog] = useState(false);
  const [inputMethod, setInputMethod] = useState<"upload" | "drive">("upload");
  const [driveLink, setDriveLink] = useState("");
  const [emailCopied, setEmailCopied] = useState(false);
  const [drivePreviewData, setDrivePreviewData] = useState<DrivePreviewResponse | null>(null);
  const [drivePreviewError, setDrivePreviewError] = useState<string | null>(null);
  const [previewDialogOpen, setPreviewDialogOpen] = useState(false);

  // Fetch dynamic batch list with pagination
  const { data: batchList, isLoading, isError, error, refetch } = useBatchList(page, itemsPerPage);
  const { data: pipelinesData, isLoading: pipelinesLoading } = usePipelines();
  const { data: serviceAccountData, isLoading: serviceAccountLoading } = useServiceAccountEmail(inputMethod === "drive");
  const createBatch = useCreateBatch();
  const drivePreview = useDrivePreview();
  const retryBatch = useRetryBatch();
  const { status: sessionStatus } = useSession();
  const { data: jobsData, isLoading: jobsLoading } = useJobs();
  const jobs = jobsData?.jobs || [];
  const [dialogOpen, setDialogOpen] = useState(false);
  const [retryingBatchId, setRetryingBatchId] = useState<string | null>(null);
  const [pendingRetryBatchId, setPendingRetryBatchId] = useState<string | null>(null);

  const executeRetry = async (batchRunId: string, jobId?: string) => {
    const currentSession = await getSession();
    const accessToken = currentSession?.accessToken as string;
    if (!accessToken) {
      toast.error("Missing auth token. Please sign out and sign in again.");
      return;
    }
    setRetryingBatchId(batchRunId);
    retryBatch.mutate(
      { batchRunId, accessToken, workflow_job_id: jobId || selectedJob || undefined },
      {
        onSuccess: () => {
          setRetryingBatchId(null);
          refetch();
        },
        onError: () => {
          setRetryingBatchId(null);
          refetch();
        },
      },
    );
  };

  const handleRetry = (batchRunId: string) => {
    if (!selectedJob && jobs.length > 0) {
      setPendingRetryBatchId(batchRunId);
      setShowJobDialog(true);
    } else {
      executeRetry(batchRunId);
    }
  };

  const handleZipFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const fileExtension = file.name.split(".").pop()?.toLowerCase();
      if (fileExtension === "zip") {
        setZipFile(file);
      } else {
        alert("Please select only ZIP");
        event.target.value = "";
      }
    }
  };

  const handleCsvFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const fileExtension = file.name.split(".").pop()?.toLowerCase();
      if (fileExtension === "csv") {
        setCsvFile(file);
      } else {
        alert("Please select only CSV files");
        event.target.value = "";
      }
    }
  };

  const [validationError, setValidationError] = useState<BatchCreateError | null>(null);
  const normalizedValidationError = normalizeValidationError(validationError);

  // Single utility to reset all dialog-related state
  const resetDialog = () => {
    setBatchName("");
    setSelectedPipeline("");
    setZipFile(null);
    setCsvFile(null);
    setScheduledAt(null);
    setShowSchedulePicker(false);
    setValidationError(null);
    setInputMethod("upload");
    setDriveLink("");
    setEmailCopied(false);
    setDrivePreviewData(null);
    setDrivePreviewError(null);
    setPreviewDialogOpen(false);
    if (createBatch.reset) {
      // Clear mutation state (errors/loading) if supported
      createBatch.reset();
    }
  };

  const handleUpload = async () => {
    if (inputMethod === "upload" && (!zipFile || !csvFile || !batchName.trim() || !selectedPipeline)) {
      return;
    }
    if (inputMethod === "drive" && (!driveLink.trim() || !batchName.trim() || !selectedPipeline)) {
      return;
    }
    const currentSession = await getSession();
    const accessToken = currentSession?.accessToken as string;
    if (!accessToken) {
      console.warn("Missing auth token. Please sign out and sign in again.");
    }
    setValidationError(null); // reset previous error state
    const payload =
      inputMethod === "drive"
        ? {
            batch_name: batchName.trim(),
            pipeline_name: selectedPipeline,
            drive_link: driveLink.trim(),
            accessToken,
            scheduled_at: scheduledAt || undefined,
          }
        : {
            batch_name: batchName.trim(),
            pipeline_name: selectedPipeline,
            csv_file: csvFile!,
            images_zip_file: zipFile!,
        accessToken,
        scheduled_at: scheduledAt || undefined,
        workflow_job_id: selectedJob || undefined,
      };
    createBatch.mutate(payload, {
      onSuccess: () => {
        toast.success(
          scheduledAt ? "Batch scheduled successfully" : "Batch submitted successfully",
        );
        setDialogOpen(false);
        resetDialog();
        refetch();
      },
      onError: (e: unknown) => {
        const maybeValidation = e as BatchCreateError;
        const normalized = normalizeValidationError(maybeValidation);
        if (normalized) {
          setValidationError(maybeValidation);
          toast.error(
            `${normalized.message || "Validation failed"}: ${normalized.count} ${normalized.itemLabel}`,
          );
        } else {
          toast.error(maybeValidation?.message || "Failed to create batch");
        }
      },
    });
  };

  const handleDrivePreview = async () => {
    setPreviewDialogOpen(true);
    setDrivePreviewError(null);
    const currentSession = await getSession();
    const accessToken = currentSession?.accessToken as string;
    if (!accessToken) {
      toast.error("Missing auth token. Please sign out and sign in again.");
      return;
    }
    drivePreview.mutate(
      { drive_link: driveLink.trim(), pipeline_name: selectedPipeline, accessToken },
      {
        onSuccess: (data) => {
          setDrivePreviewData(data);
          setDrivePreviewError(null);
        },
        onError: (e: unknown) => {
          const msg = (e as Error)?.message || "Failed to preview Drive folder";
          setDrivePreviewError(msg);
          toast.error(msg);
        },
      },
    );
  };

  // Track processing & queued tasks & spawn pollers
  const activeBatches = (batchList?.items || []).filter((b) => {
    const s = b.status?.toLowerCase();
    return (s === "processing" || s === "queued") && b.id;
  });
  const [completedBatchRunIds, setCompletedBatchRunIds] = useState<Set<string>>(new Set());

  useEffect(() => {
    requestNotificationPermission();
  }, []);

  // Check for stored job on mount from current session
  useEffect(() => {
    const storedJob = sessionStorage.getItem("selectedJob");
    if (storedJob) {
      setSelectedJob(storedJob);
    }
  }, []);

  // Handle job selection
  const handleJobSelect = (jobId: string) => {
    setSelectedJob(jobId);
    sessionStorage.setItem("selectedJob", jobId);
    setShowJobDialog(false);
    // If this was triggered by trying to open the batch dialog, open it now
    if (pendingBatchDialog) {
      setPendingBatchDialog(false);
      setDialogOpen(true);
    }
    // If this was triggered by trying to retry a batch, execute retry now
    if (pendingRetryBatchId) {
      const batchId = pendingRetryBatchId;
      setPendingRetryBatchId(null);
      executeRetry(batchId, jobId);
    }
  };

  const handleOpenBatchDialog = () => {
    if (!selectedJob && jobs.length > 0) {
      setPendingBatchDialog(true);
      setShowJobDialog(true);
    } else {
      resetDialog();
      setDialogOpen(true);
    }
  };

  return (
    <div className="p-6">
      {/* Job Selection Dialog */}
      <Dialog
        open={showJobDialog}
        onOpenChange={(open) => {
          if (!open) {
            setShowJobDialog(false);
            setPendingBatchDialog(false);
            setPendingRetryBatchId(null);
          }
        }}
      >
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Select a Job</DialogTitle>
            <DialogDescription>
              Please select a job to continue with batch processing
            </DialogDescription>
          </DialogHeader>
          <div className="py-4">
            <Select onValueChange={handleJobSelect}>
              <SelectTrigger className="w-full h-12 bg-gray-50">
                <SelectValue placeholder="Choose a job" />
              </SelectTrigger>
              <SelectContent>
                {jobsLoading ? (
                  <SelectItem value="loading" disabled>
                    Loading jobs...
                  </SelectItem>
                ) : jobs.length === 0 ? (
                  <SelectItem value="empty" disabled>
                    No jobs available
                  </SelectItem>
                ) : (
                  jobs.map((job: Job) => {
                    const { displayId, displayName } = formatJobDisplay(job);
                    return (
                      <SelectItem key={job.id} value={job.id}>
                        <div className="flex items-center gap-2">
                          <span className="text-sm text-gray-500 bg-gray-100 px-2 py-0.5 rounded border-2 border-orange-400 font-medium w-[100px] text-center inline-block truncate">
                            {displayId.toUpperCase()}
                          </span>
                          <span className="truncate max-w-[200px]">{displayName}</span>
                        </div>
                      </SelectItem>
                    );
                  })
                )}
              </SelectContent>
            </Select>
          </div>
        </DialogContent>
      </Dialog>

      <div className="flex justify-between items-center mb-10">
        <div>
          <h1 className="text-4xl font-bold mb-4">Batch Processing</h1>
          <h5 className="text-gray-600">View and manage your batch processing history</h5>
        </div>
        <div className="flex items-center gap-4">
          {jobs.length > 0 && (
            <div className="flex items-center gap-2">
              <span className="text-sm font-medium text-gray-600">Job:</span>
              <Select onValueChange={handleJobSelect} value={selectedJob}>
                <SelectTrigger className="w-[300px] h-12 bg-gray-50">
                  {selectedJob ? (
                    (() => {
                      const selectedJobData = jobs.find((t: Job) => t.id === selectedJob);
                      if (!selectedJobData)
                        return <span className="text-gray-500">Select a job</span>;
                      const { displayId, displayName } = formatJobDisplay(selectedJobData);
                      return (
                        <div className="flex items-center gap-2">
                          <span className="text-sm text-gray-500 bg-gray-100 px-2 py-0.5 rounded border-1 border-orange-400 font-medium w-[100px] text-center inline-block truncate">
                            {displayId.toUpperCase()}
                          </span>
                          <span className="truncate max-w-[200px]">{displayName}</span>
                        </div>
                      );
                    })()
                  ) : (
                    <span className="text-gray-500">Select a job</span>
                  )}
                </SelectTrigger>
                <SelectContent>
                  {jobsLoading ? (
                    <SelectItem value="loading" disabled>
                      Loading jobs...
                    </SelectItem>
                  ) : (
                    jobs.map((job: Job) => {
                      const { displayId, displayName } = formatJobDisplay(job);
                      return (
                        <SelectItem key={job.id} value={job.id}>
                          <div className="flex items-center gap-2">
                            <span className="text-sm text-gray-500 bg-gray-100 px-2 py-0.5 rounded border-1 border-orange-400 font-medium w-[100px] text-center inline-block truncate">
                              {displayId.toUpperCase()}
                            </span>
                            <span className="truncate max-w-[200px]">{displayName}</span>
                          </div>
                        </SelectItem>
                      );
                    })
                  )}
                </SelectContent>
              </Select>
            </div>
          )}
          <Dialog
            open={dialogOpen}
            onOpenChange={(o) => {
              // Closing: permit (close button or programmatic after success).
              if (!o) {
                setDialogOpen(false);
              }
            }}
          >
            {/* The button that opens the modal */}
            <Button
              className="bg-purple-500 text-white h-12 text-md px-6"
              onClick={handleOpenBatchDialog}
            >
              + Run New Batch
            </Button>

            {/* The modal content */}
            <DialogContent
              // Prevent closing via outside click or ESC; only the explicit close button or programmatic success closes.
              onInteractOutside={(e) => e.preventDefault()}
              onEscapeKeyDown={(e) => e.preventDefault()}
              className="sm:max-w-2xl max-w-[95vw] max-h-[90vh] overflow-y-auto"
            >
              <DialogHeader>
                <DialogTitle>Run New Batch</DialogTitle>
                <DialogDescription>
                  Upload files or use Google Drive to start processing
                </DialogDescription>
              </DialogHeader>

              <div className="py-4">
                <Input
                  placeholder="Enter batch name.."
                  className="h-12 bg-gray-50"
                  onChange={(e) => setBatchName(e.target.value)}
                />
              </div>

              <div className="pb-4">
                <h3 className="font-semibold mb-2">Select pipeline to run</h3>
                <Select
                  onValueChange={(value) => {
                  setSelectedPipeline(value);
                  setDrivePreviewData(null);
                  setDrivePreviewError(null);
                }}
                  disabled={pipelinesLoading}
                >
                  <SelectTrigger className="w-full h-12 bg-gray-50">
                    <SelectValue
                      placeholder={
                        pipelinesLoading
                          ? "Loading pipelines..."
                          : selectedPipeline || "Choose a pipeline"
                      }
                    />
                  </SelectTrigger>
                  <SelectContent className="max-h-80 overflow-y-auto">
                    {(() => {
                      const all = pipelinesData?.pipelines || [];
                      const production = all.filter((p) => p.type === "production");
                      const others = all.filter((p) => p.type !== "production");
                      const hasProd = production.length > 0;
                      const hasOthers = others.length > 0;
                      return (
                        <div>
                          {hasProd && (
                            <div>
                              <div className="px-2 py-1 text-xs font-semibold text-gray-500 uppercase tracking-wide">
                                Production Pipelines
                              </div>
                              {production.map((p) => (
                                <SelectItem key={p.name} value={p.name}>
                                  {p.name}
                                </SelectItem>
                              ))}
                            </div>
                          )}
                          {hasProd && hasOthers && <div className="my-2 border-t" />}
                          {hasOthers && (
                            <div>
                              <div className="px-2 py-1 text-xs font-semibold text-gray-500 uppercase tracking-wide">
                                Other Pipelines
                              </div>
                              {others.map((p) => (
                                <SelectItem key={p.name} value={p.name}>
                                  {p.name}
                                  {p.type === "experimental" && (
                                    <span className="ml-1 text-[10px] text-orange-500">
                                      (experimental)
                                    </span>
                                  )}
                                </SelectItem>
                              ))}
                            </div>
                          )}
                          {!hasProd && !hasOthers && (
                            <div className="px-2 py-2 text-sm text-gray-500">
                              No pipelines available
                            </div>
                          )}
                        </div>
                      );
                    })()}
                  </SelectContent>
                </Select>
              </div>

              <Tabs
              value={inputMethod}
              onValueChange={(v) => {
                setInputMethod(v as "upload" | "drive");
                setValidationError(null);
              }}
            >
              <TabsList className="w-full mb-4">
                <TabsTrigger value="upload" className="flex-1">Upload Files</TabsTrigger>
                <TabsTrigger value="drive" className="flex-1">Google Drive</TabsTrigger>
              </TabsList>

              <TabsContent value="upload">
                <div className="flex flex-row gap-x-6 w-full">
                <div className="w-1/2">
                  <h3 className="font-semibold mb-4">Images ZIP</h3>
                  <div className="relative">
                    {!zipFile ? (
                      <label
                        htmlFor="zip-upload"
                        className="text-center text-sm border border-dashed rounded-md p-10 flex flex-col justify-center items-center transition-colors text-gray-600 hover:bg-gray-100 cursor-pointer"
                      >
                        <Upload />
                        <span className="mt-2">Click to select ZIP</span>
                        <input
                          type="file"
                          accept=".zip"
                          onChange={handleZipFileUpload}
                          className="hidden"
                          id="zip-upload"
                        />
                      </label>
                    ) : (
                      <div className="text-center text-sm border border-dashed rounded-md p-10 flex flex-col justify-center items-center text-gray-700 border-gray-300 bg-white">
                        <Upload className="text-purple-600" />
                        <div className="mt-2 flex flex-col items-center">
                          <div className="truncate max-w-36" title={zipFile.name}>
                            {zipFile.name}
                          </div>
                          <button
                            type="button"
                            className="text-xs text-red-600 hover:underline mt-2"
                            onClick={() => {
                              setZipFile(null);
                              setValidationError(null);
                            }}
                          >
                            Remove file
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
                <div className="w-1/2">
                  <h3 className="font-semibold mb-4">CSV File</h3>
                  <div className="relative">
                    {!csvFile ? (
                      <label
                        htmlFor="csv-upload"
                        className="text-center text-sm border border-dashed rounded-md p-10 flex flex-col justify-center items-center transition-colors text-gray-600 hover:bg-gray-100 cursor-pointer"
                      >
                        <Upload />
                        <span className="mt-2">Click to select CSV</span>
                        <input
                          type="file"
                          accept=".csv"
                          onChange={handleCsvFileUpload}
                          className="hidden"
                          id="csv-upload"
                        />
                      </label>
                    ) : (
                      <div className="text-center text-sm border border-dashed rounded-md p-10 flex flex-col justify-center items-center text-gray-700 border-gray-300 bg-white">
                        <Upload className="text-purple-600" />
                        <div className="mt-2 flex flex-col items-center">
                          <div className="truncate max-w-36" title={csvFile.name}>
                            {csvFile.name}
                          </div>
                          <button
                            type="button"
                            className="text-xs text-red-600 hover:underline mt-2"
                            onClick={() => {
                              setCsvFile(null);
                              setValidationError(null);
                            }}
                          >
                            Remove file
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </div></TabsContent>

              <TabsContent value="drive">
                <div className="space-y-4">
                  {/* Service account email */}
                  <div className="bg-gray-50 border rounded-md p-4 space-y-2">
                    <p className="text-sm font-medium text-gray-700">Share your Drive folder with this service account:</p>
                    {serviceAccountLoading ? (
                      <div className="h-9 bg-gray-200 rounded-md animate-pulse" />
                    ) : serviceAccountData?.email ? (
                      <div className="flex items-center gap-2">
                        <code className="flex-1 text-sm bg-white border rounded-md px-3 py-2 font-mono text-gray-800 truncate">
                          {serviceAccountData.email}
                        </code>
                        <Button
                          type="button"
                          variant="outline"
                          size="icon"
                          className="shrink-0"
                          onClick={() => {
                            navigator.clipboard.writeText(serviceAccountData.email);
                            setEmailCopied(true);
                            toast.success("Email copied to clipboard");
                            setTimeout(() => setEmailCopied(false), 2000);
                          }}
                        >
                          {emailCopied ? <Check className="h-4 w-4 text-green-600" /> : <Copy className="h-4 w-4" />}
                        </Button>
                      </div>
                    ) : (
                      <p className="text-sm text-red-500">Failed to load service account email</p>
                    )}
                  </div>

                  {/* Instructions */}
                  <ol className="text-sm text-gray-600 space-y-1 list-decimal list-inside">
                    <li>Copy the service account email above</li>
                    <li>Share your Google Drive folder with this email (Viewer access is sufficient)</li>
                    <li>Paste the folder link below</li>
                  </ol>
                  <p className="text-xs text-gray-500">The folder must contain exactly 1 CSV file and subdirectories with image files.</p>

                  {/* Drive link input */}
                  <Input
                    placeholder="https://drive.google.com/drive/folders/..."
                    className="h-12 bg-gray-50"
                    value={driveLink}
                    onChange={(e) => {
                      setDriveLink(e.target.value);
                      setDrivePreviewData(null);
                      setDrivePreviewError(null);
                    }}
                  />

                  {/* Preview panel */}
                  <DrivePreviewPanel
                    driveLink={driveLink}
                    pipelineName={selectedPipeline}
                    previewData={drivePreviewData}
                    isLoading={drivePreview.isPending}
                    error={drivePreviewError}
                    onPreview={handleDrivePreview}
                    onOpenDialog={() => setPreviewDialogOpen(true)}
                  />
                </div>
              </TabsContent>
            </Tabs>

              {/* Validation error display */}
              {normalizedValidationError ? (
                <div className="mt-4 bg-red-50 border border-red-200 rounded-md p-3 max-h-48 overflow-y-auto text-xs">
                  <div className="font-semibold text-red-700 mb-1">
                    {normalizedValidationError.message} ({normalizedValidationError.count}{" "}
                    {normalizedValidationError.itemLabel})
                  </div>
                  <ul className="list-disc pl-5 space-y-0.5 text-red-800">
                    {normalizedValidationError.items.slice(0, 25).map((item, index) => (
                      <li
                        key={`${item}-${index}`}
                        className="whitespace-normal break-words"
                        title={item}
                      >
                        {item}
                      </li>
                    ))}
                  </ul>
                  {normalizedValidationError.items.length > 25 && (
                    <div className="mt-1 italic text-red-600">
                      + {normalizedValidationError.items.length - 25} more...
                    </div>
                  )}
                </div>
              ) : null}

